using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. Strongly-typed metadata retrieval ---
// JsonSerializerOptions.Default uses the reflection-based resolver.
var options = JsonSerializerOptions.Default;

// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> typedInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Strongly-typed info for: {typedInfo.Type.Name}");
Console.WriteLine($"  Properties: {string.Join(", ", typedInfo.Properties.Select(p => p.Name))}");

// --- 2. Probe without throwing ---
// Use a source-generated context that only knows about Person.
var limited = new JsonSerializerOptions { TypeInfoResolver = MyContext.Default };

if (limited.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? personInfo))
{
    Console.WriteLine($"\nTryGetTypeInfo<Person> succeeded → {personInfo.Type.Name}");
}

// Order is NOT registered in MyContext, so this returns false — no exception.
if (limited.TryGetTypeInfo<Order>(out JsonTypeInfo<Order>? orderInfo))
{
    Console.WriteLine($"\nTryGetTypeInfo<Order> succeeded → {orderInfo.Type.Name}");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo<Order> returned false — metadata not available (no exception!)");
}

// --- Types ---
record Person(string Name, int Age);
record Order(int Id, decimal Total);

[JsonSerializable(typeof(Person))]
partial class MyContext : JsonSerializerContext;

